const type = $('On form submission').first().json['Tipe Dokumen'];
const formatted = $input.first().json.text || $input.first().json.response?.text || $input.first().json.output || '';
const timestamp = new Date().toISOString().slice(0, 10);
const fileName = `formatted_${type}_${timestamp}.txt`;

if (!formatted || formatted.trim().length === 0) {
  throw new Error('AI tidak menghasilkan output. Coba lagi.');
}

return [{
  json: { fileName },
  binary: {
    data: {
      data: Buffer.from(formatted, 'utf-8').toString('base64'),
      mimeType: 'text/plain',
      fileName
    }
  }
}];
